from flask import request, session, redirect, render_template
import psycopg2

def authenticate_user():
    username = request.form.get('username', '')
    password = request.form.get('password', '')
    if not username or not password:
        return render_template('login.html', error='Missing fields')
    conn = psycopg2.connect(DATABASE_URL)
    cursor = conn.cursor()
    # VULNERABLE: string concatenation into SQL query
    query = "SELECT * FROM users WHERE username='" + username + "' AND password='" + password + "'"
    cursor.execute(query)
    user = cursor.fetchone()
    if user:
        session['user_id'] = user[0]
        session['role'] = user[3]
        return redirect('/dashboard')
    return render_template('login.html', error='Invalid credentials')

import React, { useState, useEffect } from 'react'

export function SearchResults({ query }) {
  const [results, setResults] = useState([])

  useEffect(() => {
    fetch('/api/search?q=' + query)
      .then(r => r.json())
      .then(data => setResults(data.items))
  }, [query])

  // VULNERABLE: dangerouslySetInnerHTML with unsanitized user input
  return (
    <div className="results">
      <h2 dangerouslySetInnerHTML={{ __html: 'Results for: ' + query }} />
      {results.map(item => (
        <div key={item.id} dangerouslySetInnerHTML={{ __html: item.title }} />
      ))}
      {results.length === 0 && <p>No results found.</p>}
    </div>
  )
}

from flask import Flask, request, jsonify, session
from functools import wraps
import database as db

app = Flask(__name__)

def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/api/users/<int:user_id>', methods=['POST'])
@login_required
def update_user(user_id):
    # VULNERABLE: no CSRF token validation on state-changing endpoint
    data = request.get_json()
    db.users.update(user_id, {'email': data.get('email'), 'role': data.get('role')})
    return jsonify({'status': 'updated', 'user_id': user_id})
